/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(LedgerJournalTransDaily, LedgerJournalTrans_ETGICDestinationEntity), FormControlEventType::Lookup)]
public static void LedgerJournalTrans_ETGICDestinationEntity_OnLookup(FormControl sender, FormControlEventArgs e)
{
    if(ETGACFParameters::find().EnableIntercompanyTransactions == NoYes::Yes)
    {
        SysTableLookup sysTableLookUp;
        QueryBuildDataSource qbds;
        Query query = new Query();

        qbds = query.addDataSource(tableNum(DataArea));

        sysTableLookUp = SysTableLookup::newParameters(tableNum(DataArea), sender);

        sysTableLookUp.addLookupfield(fieldNum(DataArea, id));
        sysTableLookUp.addLookupfield(fieldNum(DataArea, name));

        sysTableLookUp.parmQuery(query);
        sysTableLookUp.performFormLookup();

        FormControlCancelableSuperEventArgs cancelableSuperEventArgs = e as FormControlCancelableSuperEventArgs;
        cancelableSuperEventArgs.CancelSuperCall();
    }
}
